using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a new sketch on the xy plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xyPlane = rootComp->xYConstructionPlane();
    if (!xyPlane)
        return false;
    Ptr sketch = sketches->add(xyPlane);
    if (!sketch)
        return false;

    // Draw three lines.
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr line1 = sketchLines->addByTwoPoints(Point3D::create(0, 0, 0), Point3D::create(3, 1, 0));
    if (!line1)
        return false;
    Ptr line2 = sketchLines->addByTwoPoints(Point3D::create(4, 3, 0), Point3D::create(2, 4, 0));
    if (!line2)
        return false;
    Ptr line3 = sketchLines->addByTwoPoints(Point3D::create(-1, 0, 0), Point3D::create(0, 4, 0));
    if (!line3)
        return false;

    // Draw circle tangent to the lines.
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;

    Ptr circle = sketchCircles->addByThreeTangents(line1, line2, line3, Point3D::create(0, 0, 0));
    if (!circle)
        return false;

    // Apply tangent contstraints to maintain the relationship.
    Ptr constraints = sketch->geometricConstraints();
    if (!constraints)
        return false;

    Ptr constraint1 = constraints->addTangent(circle, line1);
    if (!constraint1)
        return false;

    Ptr constraint2 = constraints->addTangent(circle, line2);
    if (!constraint2)
        return false;

    Ptr constraint3 = constraints->addTangent(circle, line3);
    if (!constraint3)
        return false;


    return true;
}
